<script setup lang="ts">import{ref}from'vue';import{onShow}from'@dcloudio/uni-app';import PageHeader from'../../components/PageHeader.vue';import{medicalApi,type VisitSummary}from'../../api/medical';import{currentPatient}from'../../stores/session';const tab=ref(0),records=ref<VisitSummary[]>([]),loading=ref(false);async function load(){const patient=currentPatient.value;if(!patient)return;loading.value=true;try{records.value=await medicalApi.visits(patient.patientId)}finally{loading.value=false}}onShow(load)</script>
<template><view class="page-shell"><PageHeader title="病历与报告" subtitle="统一查看历次就诊资料"/><view class="overview"><view class="card"><text>{{records.length}}</text><text>就诊记录</text></view><view class="card"><text>{{records.filter(item=>item.archiveStatus==='archived').length}}</text><text>已归档病历</text></view><view class="card"><text>{{records.filter(item=>item.diagnosis).length}}</text><text>诊断记录</text></view></view><view class="tabs card"><text v-for="(item,index) in ['电子病历','检查报告','检验报告']" :key="item" :class="{active:tab===index}" @tap="tab=index">{{item}}</text></view><view v-if="loading" class="record card">正在加载就诊记录…</view><view v-for="item in records" :key="item.registerId" class="record card"><view class="timeline"><view/><view/></view><view class="record-main"><view class="record-head"><text>{{item.departmentName||'门诊科室'}}</text><text>{{item.archiveStatus==='archived'?'已归档':'整理中'}}</text></view><text>{{item.visitDate||''}} · {{item.physicianName||'门诊医生'}}</text><view class="diagnosis"><text>诊断</text><text>{{item.diagnosis||item.preliminaryDiagnosis||'暂无诊断信息'}}</text></view><view class="record-links"><text>病历详情 ›</text><text>检查结果 ›</text><text>处方 ›</text></view></view></view><view v-if="!loading&&!records.length" class="record card">暂无可查看的就诊记录</view></view></template>
<style scoped lang="scss">.overview{display:grid;grid-template-columns:repeat(3,1fr);gap:14rpx}.overview view{padding:24rpx 5rpx;display:flex;flex-direction:column;align-items:center;gap:8rpx}.overview text:first-child{color:#2878ff;font-size:34rpx;font-weight:700}.overview text:last-child{color:#738097;font-size:20rpx}.tabs{margin-top:22rpx;display:flex}.tabs text{flex:1;padding:25rpx 8rpx;text-align:center;color:#758198;font-size:22rpx}.tabs .active{color:#2878ff;border-bottom:5rpx solid #2878ff}.record{margin-top:18rpx;padding:25rpx;display:flex}.timeline{width:38rpx;display:flex;flex-direction:column;align-items:center}.timeline view:first-child{width:18rpx;height:18rpx;border:5rpx solid #74adff;border-radius:50%;background:#fff}.timeline view:last-child{width:3rpx;flex:1;margin-top:7rpx;background:#dce8f8}.record-main{flex:1}.record-head{display:flex;justify-content:space-between}.record-head text:first-child{font-size:27rpx;font-weight:700}.record-head text:last-child{color:#16a47c;font-size:19rpx}.record-main>text{display:block;margin-top:9rpx;color:#7d899d;font-size:20rpx}.diagnosis{margin-top:18rpx;padding:17rpx;border-radius:16rpx;background:#f5f8fd}.diagnosis text:first-child{margin-right:14rpx;color:#2878ff;font-size:19rpx}.diagnosis text:last-child{font-size:23rpx}.record-links{display:flex;gap:26rpx;margin-top:18rpx;color:#2878ff;font-size:20rpx}</style>
